import React, { useState, useRef, useEffect } from "react";
import Sidebar from "../components/Sidebar";
import { useAuth } from "../context/AuthContext";

const STARTERS = [
  "How do I become a Data Scientist?",
  "What skills are trending in 2025?",
  "How to prepare for a Google interview?",
  "Difference between React and Angular?",
];

export default function Assistant() {

const { user } = useAuth();

const [messages,setMessages]=useState([
{
role:"assistant",
content:`Hi ${user?.name?.split(" ")[0]||"there"} 👋  
I'm your AI Career Assistant. Ask me anything about tech careers!`
}
]);

const [input,setInput]=useState("");
const [loading,setLoading]=useState(false);
const [error,setError]=useState("");

const bottomRef=useRef(null);

useEffect(()=>{
bottomRef.current?.scrollIntoView({behavior:"smooth"});
},[messages]);

// Voice input
const startVoice=()=>{
const speech=new window.webkitSpeechRecognition();
speech.lang="en-US";
speech.onresult=(e)=>{
setInput(e.results[0][0].transcript);
};
speech.start();
};

const send=async(text)=>{

const msg=text||input.trim();
if(!msg||loading)return;

setInput("");
setError("");

const newMessages=[...messages,{role:"user",content:msg}];
setMessages(newMessages);
setLoading(true);

try{

const res=await fetch("/api/ai/chat",{
method:"POST",
headers:{"Content-Type":"application/json"},
body:JSON.stringify({messages:newMessages})
});

const data=await res.json();

if(!data.success) throw new Error(data.message);

setMessages(prev=>[
...prev,
{role:"assistant",content:data.reply}
]);

}catch(e){

setError("⚠️ "+e.message);

}finally{

setLoading(false);

}

};

const formatMsg=(text)=>{
return text.split("\n").map((line,i)=>{
if(line.startsWith("- ")||line.startsWith("• "))
return <p key={i}>• {line.slice(2)}</p>;
if(line==="")return <br key={i}/>;
return <p key={i}>{line}</p>;
});
};

return(

<div style={{
display:"flex",
height:"100vh",
background:"#0f172a",
color:"#e2e8f0"
}}>

<Sidebar/>

<div style={{
flex:1,
display:"flex",
flexDirection:"column"
}}>

{/* HEADER */}

<div style={{
padding:"18px 25px",
borderBottom:"1px solid #1e293b",
background:"#020617"
}}>
<h2>🤖 AI Career Assistant</h2>
<p style={{fontSize:13,color:"#94a3b8"}}>
Career guidance, skills, interviews & roadmap
</p>
</div>


{/* CHAT AREA */}

<div style={{
flex:1,
overflowY:"auto",
padding:"25px",
maxWidth:900,
margin:"0 auto",
width:"100%"
}}>

{/* STARTER CHIPS */}

{messages.length<=1 &&(

<div style={{
display:"flex",
flexWrap:"wrap",
gap:10,
marginBottom:20
}}>

{STARTERS.map(s=>(
<button
key={s}
onClick={()=>send(s)}
style={{
background:"#1e293b",
border:"1px solid #334155",
padding:"8px 14px",
borderRadius:20,
cursor:"pointer",
color:"#cbd5f5",
fontSize:13
}}>
{s}
</button>
))}

</div>

)}

{/* CHAT */}

{messages.map((m,i)=>(

<div key={i} style={{
display:"flex",
justifyContent:m.role==="user"?"flex-end":"flex-start",
marginBottom:20
}}>

{m.role==="assistant" &&(

<div style={{
width:36,
height:36,
borderRadius:"50%",
background:"linear-gradient(135deg,#3b82f6,#8b5cf6)",
display:"flex",
alignItems:"center",
justifyContent:"center",
marginRight:10
}}>
🤖
</div>

)}

<div style={{
background:m.role==="user"?"#2563eb":"#1e293b",
padding:"10px 14px",
borderRadius:14,
maxWidth:"70%",
fontSize:14,
lineHeight:1.6
}}>
{m.role==="assistant"
?formatMsg(m.content)
:m.content}
</div>

</div>

))}

{/* TYPING ANIMATION */}

{loading&&(
<div style={{display:"flex",gap:8}}>
<div style={{
width:8,height:8,
background:"#3b82f6",
borderRadius:"50%",
animation:"pulse 1s infinite"
}}/>
<div style={{
width:8,height:8,
background:"#3b82f6",
borderRadius:"50%",
animation:"pulse 1s infinite .2s"
}}/>
<div style={{
width:8,height:8,
background:"#3b82f6",
borderRadius:"50%",
animation:"pulse 1s infinite .4s"
}}/>
</div>
)}

{error&&<p style={{color:"#f87171"}}>{error}</p>}

<div ref={bottomRef}/>

</div>


{/* INPUT BAR */}

<div style={{
padding:18,
borderTop:"1px solid #1e293b",
background:"#020617"
}}>

<div style={{
display:"flex",
gap:10,
maxWidth:900,
margin:"0 auto"
}}>

<button
onClick={startVoice}
style={{
background:"#1e293b",
border:"1px solid #334155",
borderRadius:10,
padding:"8px 12px",
cursor:"pointer"
}}>
🎙
</button>

<input
value={input}
onChange={e=>setInput(e.target.value)}
onKeyDown={e=>e.key==="Enter"&&send()}
placeholder="Ask about careers, skills, roadmap..."
style={{
flex:1,
padding:"10px",
borderRadius:10,
border:"1px solid #334155",
background:"#1e293b",
color:"#fff"
}}
/>

<button
onClick={()=>send()}
disabled={!input.trim()||loading}
style={{
background:"#3b82f6",
border:"none",
padding:"10px 16px",
borderRadius:10,
color:"#fff",
cursor:"pointer"
}}>
Send →
</button>

</div>

</div>

</div>

</div>

);

}
